mapper.insert:
INSERT INTO tbl_payment (
    payment_code, order_code, buyer_id, seller_id, work_id, auction_id,
    original_amount, total_price, total_fee,
    payment_purpose, pay_method, card_id, status
) VALUES (
    #{paymentCode}, #{orderCode}, #{buyerId}, #{sellerId}, #{workId}, #{auctionId},
    #{originalAmount}, #{totalPrice}, #{totalFee},
    #{paymentPurpose}, #{payMethod}, #{cardId}, #{status}
)

mapper.select:
SELECT id, payment_code, order_code, total_price, total_fee,
       payment_purpose, pay_method, status, paid_at, created_datetime
FROM tbl_payment
WHERE buyer_id = #{buyerId}
ORDER BY created_datetime DESC
LIMIT #{limit} OFFSET #{offset}

mapper.update:
UPDATE tbl_payment
SET status = 'COMPLETED', paid_at = NOW()
WHERE id = #{paymentId}

UPDATE tbl_payment
SET status = 'REFUNDED', refunded_at = NOW()
WHERE id = #{paymentId}
